// // This module is designed to perform an asynchronous multiplication of two 16-bit signed inputs and store the result in a 32-bit unsigned output.
module top_module(input clk, input signed [15:0] a, input signed [15:0] b, output signed [31:0] out);reg signed [31:0] acc;
    always @(posedge clk) begin
        acc <= a * b;
    end
    assign out = acc;
endmodule
